  1	import * as React from 'react';
  2	import { getExternalStorage } from '@odf/core/components/utils';
  3	import {
  4	  StorageClassWizardStepExtensionProps as ExternalStorage,
  5	  ExternalStateValues,
  6	} from '@odf/odf-plugin-sdk/extensions';
  7	import {
  8	  fieldRequirementsTranslations,
  9	  formSettings,
 10	} from '@odf/shared/constants';
 11	import { useK8sList } from '@odf/shared/hooks/useK8sList';
 12	import { TextInputWithFieldRequirements } from '@odf/shared/input-with-requirements';
 13	import { StorageClassModel } from '@odf/shared/models';
 14	import { getName } from '@odf/shared/selectors';
 15	import { StorageClassResourceKind } from '@odf/shared/types';
 16	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 17	import validationRegEx from '@odf/shared/utils/validation';
 18	import { useYupValidationResolver } from '@odf/shared/yup-validation-resolver';
 19	import { useForm } from 'react-hook-form';
 20	import * as Yup from 'yup';
 21	import { Form, TextContent, TextVariants, Text } from '@patternfly/react-core';
 22	import { WizardDispatch, WizardState } from '../../reducer';
 23	import './create-storage-class-step.scss';
 24	
 25	export const CreateStorageClass: React.FC<CreateStorageClassProps> = ({
 26	  state,
 27	  storageClass,
 28	  externalStorage,
 29	  dispatch,
 30	  supportedExternalStorage,
 31	}) => {
 32	  const { t } = useCustomTranslation();
 33	
 34	  const {
 35	    component: Component,
 36	    schemaHandler,
 37	    displayName,
 38	  } = getExternalStorage(externalStorage, supportedExternalStorage) || {
 39	    Component: null,
 40	    displayName: '',
 41	  };
 42	
 43	  const externalStorageSchema = schemaHandler?.();
 44	
 45	  const setForm = React.useCallback(
 46	    (field: string, value: ExternalStateValues) =>
 47	      dispatch({
 48	        type: 'wizard/setCreateStorageClass',
 49	        payload: {
 50	          field,
 51	          value,
 52	        },
 53	      }),
 54	    [dispatch]
 55	  );
 56	
 57	  const [scData, scLoaded, scLoadError] =
 58	    useK8sList<StorageClassResourceKind>(StorageClassModel);
 59	
 60	  const { schema, fieldRequirements } = React.useMemo(() => {
 61	    const existingNames =
 62	      scLoaded && !scLoadError ? scData?.map((data) => getName(data)) : [];
 63	
 64	    const fieldRequirements = [
 65	      fieldRequirementsTranslations.maxChars(t, 253),
 66	      fieldRequirementsTranslations.startAndEndName(t),
 67	      fieldRequirementsTranslations.alphaNumericPeriodAdnHyphen(t),
 68	      fieldRequirementsTranslations.cannotBeUsedBefore(t),
 69	    ];
 70	
 71	    const schema = Yup.object({
 72	      'storage-class-name': Yup.string()
 73	        .required()
 74	        .max(253, fieldRequirements[0])
 75	        .matches(
 76	          validationRegEx.startAndEndsWithAlphanumerics,
 77	          fieldRequirements[1]
 78	        )
 79	        .matches(
 80	          validationRegEx.alphaNumericsPeriodsHyphensNonConsecutive,
 81	          fieldRequirements[2]
 82	        )
 83	        .test(
 84	          'unique-name',
 85	          fieldRequirements[3],
 86	          (value: string) => !existingNames.includes(value)
 87	        ),
 88	    }).concat(externalStorageSchema);
 89	
 90	    return { schema, fieldRequirements };
 91	  }, [scData, scLoadError, scLoaded, externalStorageSchema, t]);
 92	
 93	  const resolver = useYupValidationResolver(schema);
 94	  const {
 95	    control,
 96	    watch,
 97	    formState: { isValid },
 98	  } = useForm({
 99	    ...formSettings,
100	    resolver,
101	  });
102	
103	  const storageClassName: string = watch('storage-class-name');
104	
105	  React.useEffect(() => {
106	    dispatch({
107	      type: 'wizard/setStorageClass',
108	      payload: {
109	        name: isValid ? storageClassName : '',
110	      },
111	    });
112	  }, [storageClassName, dispatch, isValid]);
113	
114	  return (
115	    <Form className="odf-create-storage-class__form">
116	      <TextInputWithFieldRequirements
117	        control={control}
118	        fieldRequirements={fieldRequirements}
119	        defaultValue={storageClass.name}
120	        popoverProps={{
121	          headerContent: t('Name requirements'),
122	          footerContent: `${t('Example')}: my-storage-class`,
123	        }}
124	        formGroupProps={{
125	          label: t('StorageClass name'),
126	          fieldId: 'storage-class-name',
127	        }}
128	        textInputProps={{
129	          id: 'storage-class-name',
130	          name: 'storage-class-name',
131	          'data-test': 'storage-class-name',
132	        }}
133	      />
134	      <TextContent>
135	        <Text component={TextVariants.h4}>
136	          {t('{{displayName}} connection details', { displayName })}
137	        </Text>
138	      </TextContent>
139	      {Component && (
140	        <Component control={control} setFormState={setForm} formState={state} />
141	      )}
142	    </Form>
143	  );
144	};
145	
146	type CreateStorageClassProps = {
147	  state: WizardState['createStorageClass'];
148	  externalStorage: WizardState['backingStorage']['externalStorage'];
149	  storageClass: WizardState['storageClass'];
150	  dispatch: WizardDispatch;
151	  supportedExternalStorage: ExternalStorage[];
152	};

